// Color component extraction macros (for RGBA format: 0xRRGGBBAA)
#define WZ_COLOR_R(c) (((c) >> 24) & 0xFF)
#define WZ_COLOR_G(c) (((c) >> 16) & 0xFF)
#define WZ_COLOR_B(c) (((c) >> 8) & 0xFF)
#define WZ_COLOR_A(c) ((c) & 0xFF)
#define WZ_RGBA(r,g,b,a) (((unsigned)(r)<<24)|((unsigned)(g)<<16)|((unsigned)(b)<<8)|(unsigned)(a))

static WzDrawCommandBuffer ispc_cmds;

static void wz_push_filled_rect(WzDrawCommandBuffer* buf, float x, float y, float w, float h, unsigned color)
{
	if (!buf || buf->count >= MAX_NUM_DRAW_COMMANDS - 1) return;
	WzDrawCommand* cmd = &buf->commands[buf->count++];
	cmd->type = DrawCommandType_Rect;
	cmd->x = x; cmd->y = y; cmd->w = w; cmd->h = h; cmd->color = color;
}

static void wz_ispc_push_rect(WzDrawCommandBuffer* buf, const struct WzSlotOld* slot, int lane, unsigned color)
{
	wz_push_filled_rect(buf, slot->abs_x[lane], slot->abs_y[lane], slot->abs_width[lane], slot->abs_height[lane], color);
}

