void load_animations()
{
	bool result = SDL_EnumerateDirectory("Gifs", onFile, 0);
	if (!result)
	{
		SDL_ShowSimpleMessageBox(
			SDL_MESSAGEBOX_ERROR,
			"Fatal Error",
			SDL_GetError(),
			NULL
		);

		return SDL_APP_FAILURE;
	}
}

void WSDL_ContextCreate(WSDL_Context* context, unsigned window_width, unsigned window_height)
{
	bool success = true;
	SDL_Renderer* renderer;
	SDL_Window* window;
	TTF_TextEngine* text_engine;

	success &= SDL_SetHint(SDL_HINT_RENDER_DRIVER, "direct3d");

	success &= SDL_CreateWindowAndRenderer("my window", window_width, window_height,
		SDL_WINDOW_RESIZABLE, &window, &renderer);

	success &= SDL_SetRenderDrawBlendMode(renderer, SDL_BLENDMODE_BLEND);

	text_engine = TTF_CreateRendererTextEngine(renderer);
	success &= (bool)text_engine;

	if (!success)
	{
		SDL_ShowSimpleMessageBox(
			SDL_MESSAGEBOX_ERROR,
			"Fatal Error",
			SDL_GetError(),
			NULL
		);
	}

	context->renderer = renderer;
	context->window = window;
	context->text_engine = text_engine;
}

SDL_AppResult SDL_AppInit(void** appstate, int argc, char* argv[])
{
	bool success = false;

	WSDL_ContextCreate(&gui_window, WINDOW_WIDTH, WINDOW_HEIGHT);

	// Load fonts via wzgui atlas
	wz_set_gui(&gui_window.gui);
	{
		// Font 0: Arial 18px (default)
		size_t file_size;
		unsigned char* data = (unsigned char*)SDL_LoadFile("C:\\Windows\\Fonts\\Arial.ttf", &file_size);
		if (!data) {
			SDL_Log("Failed to load font: %s", SDL_GetError());
			SDL_Quit();
			return 1;
		}
		wz_font_load(0, data, (unsigned)file_size, 18.0f);

		// Font 1: Arial 28px (reuse same ttf data)
		wz_font_load(1, data, (unsigned)file_size, 28.0f);
		SDL_free(data);

		// Upload atlas textures
		for (unsigned fi = 0; fi < gui_window.gui.fonts_count; fi++) {
			WzFont* font = &gui_window.gui.fonts[fi];
			SDL_Texture* atlas_tex = wz_upload_font_atlas_rt(gui_window.renderer, font->atlas_bitmap, font->atlas_w, font->atlas_h);
			free(font->atlas_bitmap);
			font->atlas_bitmap = NULL;
			wz_font_set_atlas_texture(fi, (WzTexture){ .data = atlas_tex, .w = (float)font->atlas_w, .h = (float)font->atlas_h });
		}

	}

	// X icon
	{
		// TODO: Remove width and height fields of wz texture
		SDL_Surface* surface = SDL_CreateSurfaceFrom(16, 16, SDL_PIXELFORMAT_RGBA8888, wz_x_icon, 16 * 4);
		success |= (bool)surface;
		gui.x_icon = (WzTexture){ .w = surface->w, .h = surface->h, .data = SDL_CreateTextureFromSurface(gui_window.renderer, surface) };
	}


	if (!success)
	{
		SDL_ShowSimpleMessageBox(
			SDL_MESSAGEBOX_ERROR,
			"Fatal Error",
			SDL_GetError(),
			NULL
		);

		return SDL_APP_FAILURE;
	}

	load_animations();

	//wz_layout_ispc_test();

	return SDL_APP_CONTINUE;
}

void WSDL_WindowContextBegin(WSDL_Context* context)
{
	bool success = true;
	success &= SDL_SetRenderDrawColor(context->renderer, 0x20, 0x8c, 0x71, 255);
	success &= SDL_RenderClear(context->renderer);
}

WzWidget WSDL_WzBegin(WSDL_Context* context)
{
	int window_width, window_height;
	SDL_GetWindowSize(context->window, &window_width, &window_height);

	WSDL_WindowContextBegin(&gui_window);
}

bool WSDL_IsInteracting(char k)
{
	bool result = wsdl.keyboard.keys[k] == WZ_ACTIVATING || wsdl.keyboard.keys[k] == WZ_ACTIVE;

	return result;
}

SDL_AppResult SDL_AppIterate(void* appstate)
{
	unsigned time_beginning = SDL_GetTicks();

	bool success = true;

	ispc_cmds.count = 0;

	WSDL_WzBegin(&gui_window);
	wz_set_gui(&gui_window.gui);

	gui_window.gui.ticks_in_ns = SDL_GetTicksNS;
	gui_window.gui.ticks_in_ms = SDL_GetTicks;

	WSDL_WzBeginWidgets(&gui_window);

	WzWidget window = (WzWidget){ 0 };
	WzWidget ib_window = wz_vbox(window);

	WzStr strs[] = { wz_str_create("wow1"), wz_str_create("wow2"), wz_str_create("wow3") };
	static int selected_text = -1;
	static bool active;
	wz_dropdown(ib_window, strs, 3, &selected_text, &active);
	wz_label(ib_window, wz_str_create("euaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"));

	WSDL_WzEnd(&gui_window);

	if (gui_window.gui.copied_text[0])
	{
		SDL_SetClipboardText(gui_window.gui.copied_text);
		gui_window.gui.copied_text[0] = '\0';
	}

	SDL_SetRenderDrawBlendMode(gui_window.renderer, SDL_BLENDMODE_BLEND);
	WSDL_RenderCommandBuffer(gui_window.renderer, &ispc_cmds);
	SDL_RenderPresent(gui_window.renderer);

	unsigned delta_time = SDL_GetTicks() - time_beginning;
	if (delta_time < 42)
	{
		SDL_Delay(42 - delta_time);
	}

	if (!success)
	{
		SDL_ShowSimpleMessageBox(
			SDL_MESSAGEBOX_ERROR,
			"Fatal Error",
			SDL_GetError(),
			NULL
		);

		return SDL_APP_FAILURE;
	}

	events_count = 0;

	return SDL_APP_CONTINUE;
}

